import{_ as n,a,b as t,c as d,d as i,e as o,f as r,g as l}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as s,o as p,c as u,a2 as h}from"./chunks/framework.DnrXFDHb.js";const w=JSON.parse('{"title":"Gefedereerde gedistribueerde index","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Other/federated-distributed-index.md","filePath":"nl-NL/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),b={name:"nl-NL/Other/federated-distributed-index.md"};function c(g,e,k,m,j,f){return p(),u("div",null,[...e[0]||(e[0]=[h('<h1 id="gefedereerde-gedistribueerde-index" tabindex="-1">Gefedereerde gedistribueerde index <a class="header-anchor" href="#gefedereerde-gedistribueerde-index" aria-label="Permalink to &quot;Gefedereerde gedistribueerde index&quot;">​</a></h1><p>De gefedereerde gedistribueerde index laat meerdere ImgBed-sites bestandslijsten met elkaar delen.</p><p>Kort gezegd:</p><ul><li>Je kunt geselecteerde mappen van je site met anderen delen.</li><li>Je kunt deelnemen aan een ander knooppunt en de gedeelde bestandslijst van dat knooppunt naar je beheer synchroniseren.</li><li>Gefedereerde bestanden zijn vooral bedoeld om te bekijken, te zoeken en links te openen. Ze worden niet opnieuw naar je eigen opslag geüpload.</li></ul><h2 id="waar-je-dit-configureert" tabindex="-1">Waar je dit configureert <a class="header-anchor" href="#waar-je-dit-configureert" aria-label="Permalink to &quot;Waar je dit configureert&quot;">​</a></h2><p>Open:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+n+`" alt="Lokaal federatieknooppunt" loading="lazy"></p><p>De pagina heeft drie tabbladen:</p><table tabindex="0"><thead><tr><th>Tabblad</th><th>Doel</th></tr></thead><tbody><tr><td>Local Node</td><td>Je knooppunt inschakelen, publiek domein bevestigen, gedeelde mappen kiezen en uitgaande index bijwerken</td></tr><tr><td>Nodes I Joined</td><td>Andere ImgBed-knooppunten beheren waaraan je deelneemt</td></tr><tr><td>Nodes Joining Me</td><td>Verzoeken beheren van anderen die aan jouw knooppunt willen deelnemen</td></tr></tbody></table><h2 id="eerste-installatie" tabindex="-1">Eerste installatie <a class="header-anchor" href="#eerste-installatie" aria-label="Permalink to &quot;Eerste installatie&quot;">​</a></h2><ol><li>Open <code>Local Node</code>.</li><li>Schakel <code>Enable</code> in.</li><li>Selecteer mappen om te delen onder <code>Sync folders</code>.</li><li>Klik op <code>Update Outbound Index</code>.</li><li>Als ImgBed een domeinwijziging detecteert, bevestig dan dat het huidige domein klopt voordat je doorgaat.</li></ol><p>Je kunt meerdere synchronisatiemappen selecteren.</p><p>Als de lijst met synchronisatiemappen leeg is, worden alle mappen gedeeld.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="publiek-domein" tabindex="-1">Publiek domein <a class="header-anchor" href="#publiek-domein" aria-label="Permalink to &quot;Publiek domein&quot;">​</a></h3><p>Het publieke domein is de site-URL die andere knooppunten gebruiken om jouw knooppunt te bereiken.</p><p>ImgBed detecteert dit automatisch. Je hoeft het niet handmatig in te voeren. De eerste keer dat je de index bijwerkt, vraagt ImgBed of de huidige toegangs-URL het productiedomein is.</p><p>Als je later van domein verandert, vraagt een indexupdate opnieuw om bevestiging.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders bepalen welke bestanden worden gedeeld met federatieknooppunten.</p><p>Als je bijvoorbeeld alleen selecteert:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>kunnen andere knooppunten alleen bestanden in die twee directories zien.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>Dit werkt de bestandslijst bij die anderen vanaf jouw site kunnen synchroniseren.</p><p>Gebruik dit wanneer:</p><ul><li>je federatie voor het eerst inschakelt.</li><li>je bestanden uploadt die je wilt delen.</li><li>je synchronisatiemappen wijzigt.</li><li>je publieke domein verandert en je dit moet bevestigen.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> is waar je je abonneert op andere knooppunten.</p><p><img src="`+a+'" alt="Knooppunten waaraan ik deelneem" loading="lazy"></p><h3 id="toetreden-tot-een-ander-knooppunt-aanvragen" tabindex="-1">Toetreden tot een ander knooppunt aanvragen <a class="header-anchor" href="#toetreden-tot-een-ander-knooppunt-aanvragen" aria-label="Permalink to &quot;Toetreden tot een ander knooppunt aanvragen&quot;">​</a></h3><ol><li>Vraag de andere eigenaar om een uitnodigingslink.</li><li>Plak deze in het invoerveld.</li><li>Klik op <code>Request to Join</code>.</li><li>Wacht tot de andere eigenaar het verzoek goedkeurt in zijn beheer.</li></ol><p>Na goedkeuring wordt de knooppuntstatus approved.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> synchroniseert bestandslijsten vanaf knooppunten waaraan je deelneemt.</p><p>Gebruik dit wanneer:</p><ul><li>de andere eigenaar je verzoek net heeft goedgekeurd.</li><li>de andere eigenaar meldt dat gedeelde inhoud is bijgewerkt.</li><li>je alle verbonden federatieve bestandslijsten wilt verversen.</li></ul><p>Om slechts één knooppunt bij te werken, klik je op <code>Update Index</code> op de kaart van dat knooppunt.</p><p><img src="'+t+'" alt="Index bijwerken" loading="lazy"></p><h3 id="afmelden" tabindex="-1">Afmelden <a class="header-anchor" href="#afmelden" aria-label="Permalink to &quot;Afmelden&quot;">​</a></h3><p>Wil je een knooppunt niet meer synchroniseren, klik dan op <code>Unsubscribe</code>.</p><p>Na afmelden wordt de federatieve index van dat knooppunt van je lokale site verwijderd.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> is waar je verzoeken van anderen afhandelt.</p><p><img src="'+d+'" alt="Knooppunten die bij mij willen aansluiten" loading="lazy"></p><h3 id="een-uitnodigingslink-maken" tabindex="-1">Een uitnodigingslink maken <a class="header-anchor" href="#een-uitnodigingslink-maken" aria-label="Permalink to &quot;Een uitnodigingslink maken&quot;">​</a></h3><ol><li>Controleer dat het lokale knooppunt is ingeschakeld.</li><li>Klik minstens één keer op <code>Update Outbound Index</code>, zodat ImgBed het publieke domein bevestigt.</li><li>Open <code>Nodes Joining Me</code>.</li><li>Klik op <code>Reset Invitation Link</code>.</li><li>Kopieer de uitnodigingslink en stuur deze naar de andere eigenaar.</li></ol><p>Als de uitnodigingslink leeg is, is het publieke domein meestal nog niet bevestigd. Ga terug naar <code>Local Node</code> en klik op <code>Update Outbound Index</code>.</p><h3 id="deelnameverzoeken-behandelen" tabindex="-1">Deelnameverzoeken behandelen <a class="header-anchor" href="#deelnameverzoeken-behandelen" aria-label="Permalink to &quot;Deelnameverzoeken behandelen&quot;">​</a></h3><p>Wanneer iemand een verzoek indient, verschijnt dit in de lijst <code>Nodes Joining Me</code>.</p><table tabindex="0"><thead><tr><th>Actie</th><th>Betekenis</th></tr></thead><tbody><tr><td>Approve</td><td>Staat toe dat het andere knooppunt jouw gedeelde bestandslijst synchroniseert</td></tr><tr><td>Reject</td><td>Weigert het deelnameverzoek</td></tr><tr><td>Delete</td><td>Verwijdert een afgerond record</td></tr><tr><td>Check Status</td><td>Controleert of de andere kant deze relatie nog behoudt</td></tr></tbody></table><p>Na goedkeuring moet de andere kant nog <code>Update Inbound Index</code> klikken voordat jouw gedeelde bestanden daar verschijnen.</p><p><img src="'+i+'" alt="Uitgenodigd knooppunt goedkeuren" loading="lazy"></p><h2 id="berichten" tabindex="-1">Berichten <a class="header-anchor" href="#berichten" aria-label="Permalink to &quot;Berichten&quot;">​</a></h2><p>Nadat een relatie is goedgekeurd, klik je op <code>Message</code> op de knooppuntkaart.</p><p>Berichten zijn alleen bedoeld voor communicatie over de federatierelatie. Ze wijzigen geen bestanden, tags, directories of rechten.</p><p><img src="'+o+'" alt="Berichten" loading="lazy"></p><h2 id="gefedereerde-bestanden-bekijken" tabindex="-1">Gefedereerde bestanden bekijken <a class="header-anchor" href="#gefedereerde-bestanden-bekijken" aria-label="Permalink to &quot;Gefedereerde bestanden bekijken&quot;">​</a></h2><p>Ga na synchronisatie terug naar de bestandslijst in het beheer.</p><p>Bovenaan de pagina kun je wisselen tussen lokale bestanden en gefedereerde bestanden. Bij gefedereerde bestanden kun je gesynchroniseerde inhoud bekijken.</p><p>Gefedereerde bestanden zijn vooral bedoeld om te bekijken, zoeken, previewen en links te kopiëren. Het zijn geen lokale bestanden, dus je kunt ze niet verplaatsen, verwijderen, opnieuw taggen of back-uppen vanaf je eigen site.</p><p><img src="'+r+'" alt="Gefedereerde bestanden in beheer" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="waarom-moet-ik-opnieuw-aanvragen-omdat-er-geen-relatierecord-is" tabindex="-1">Waarom moet ik opnieuw aanvragen omdat er geen relatierecord is? <a class="header-anchor" href="#waarom-moet-ik-opnieuw-aanvragen-omdat-er-geen-relatierecord-is" aria-label="Permalink to &quot;Waarom moet ik opnieuw aanvragen omdat er geen relatierecord is?&quot;">​</a></h3><p>Dit betekent meestal dat de andere kant je heeft verwijderd en het record heeft weggehaald, waardoor de relatie niet meer gevonden wordt. Dien een nieuw verzoek in.</p><p><img src="'+l+'" alt="Opnieuw aanvragen zonder relatierecord" loading="lazy"></p><h3 id="waarom-zie-ik-geen-bestanden-na-deelname" tabindex="-1">Waarom zie ik geen bestanden na deelname? <a class="header-anchor" href="#waarom-zie-ik-geen-bestanden-na-deelname" aria-label="Permalink to &quot;Waarom zie ik geen bestanden na deelname?&quot;">​</a></h3><p>Controleer:</p><ol><li>De andere eigenaar heeft je verzoek goedgekeurd.</li><li>De andere eigenaar heeft <code>Update Outbound Index</code> geklikt.</li><li>Jij hebt <code>Update Inbound Index</code> geklikt.</li><li>De synchronisatiemappen van de andere eigenaar bevatten de directories die gedeeld moeten worden.</li></ol><h3 id="wat-moet-ik-doen-bij-een-gedetecteerde-domeinwijziging" tabindex="-1">Wat moet ik doen bij een gedetecteerde domeinwijziging? <a class="header-anchor" href="#wat-moet-ik-doen-bij-een-gedetecteerde-domeinwijziging" aria-label="Permalink to &quot;Wat moet ik doen bij een gedetecteerde domeinwijziging?&quot;">​</a></h3><p>Open je het beheer momenteel via het productiedomein, bevestig dan en ga door.</p><p>Gebruik je een tijdelijk adres, annuleer dan, open het beheer opnieuw via het productiedomein en probeer het opnieuw.</p><h3 id="wat-betekent-een-lege-sync-folder-lijst" tabindex="-1">Wat betekent een lege Sync Folder-lijst? <a class="header-anchor" href="#wat-betekent-een-lege-sync-folder-lijst" aria-label="Permalink to &quot;Wat betekent een lege Sync Folder-lijst?&quot;">​</a></h3><p>Een lege Sync Folder-lijst betekent dat alle mappen worden gedeeld.</p><p>Wil je alleen sommige directories delen, selecteer die mappen dan handmatig.</p><h3 id="verschil-tussen-outbound-en-inbound-indexupdates" tabindex="-1">Verschil tussen outbound en inbound indexupdates <a class="header-anchor" href="#verschil-tussen-outbound-en-inbound-indexupdates" aria-label="Permalink to &quot;Verschil tussen outbound en inbound indexupdates&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Knop</th><th>Simpele betekenis</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>Werkt bij wat anderen van mij kunnen synchroniseren</td></tr><tr><td>Update Inbound Index</td><td>Werkt bij wat ik van anderen heb gesynchroniseerd</td></tr></tbody></table>',78)])])}const q=s(b,[["render",c]]);export{w as __pageData,q as default};
